#!/usr/bin/env bash
# Generated by prepare_cd38_external_tool_inputs.py
# Run external P2Rank commands for CD38 target structures.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

if ! command -v prank >/dev/null 2>&1; then
  echo "Missing P2Rank executable: prank. Install P2Rank or add it to PATH." >&2
  exit 127
fi

# 3ROP
PDB_PATH="$SCRIPT_DIR/pdbs/3ROP.pdb"
OUT_DIR="$SCRIPT_DIR/p2rank_outputs/3ROP"
mkdir -p "$OUT_DIR"
prank predict -f "$PDB_PATH" -o "$OUT_DIR"

# 4OGW
PDB_PATH="$SCRIPT_DIR/pdbs/4OGW.pdb"
OUT_DIR="$SCRIPT_DIR/p2rank_outputs/4OGW"
mkdir -p "$OUT_DIR"
prank predict -f "$PDB_PATH" -o "$OUT_DIR"

# 3F6Y
PDB_PATH="$SCRIPT_DIR/pdbs/3F6Y.pdb"
OUT_DIR="$SCRIPT_DIR/p2rank_outputs/3F6Y"
mkdir -p "$OUT_DIR"
prank predict -f "$PDB_PATH" -o "$OUT_DIR"

